{
  "name": "Meta Wearables Prep Coach",
  "description": "A comprehensive, timed study and grading tool for Meta Reality Labs Wearables Partner Engineer interviews, featuring flashcards, coding simulations, and behavioral scenarios."
}

export enum BlockType {
  Calibration = 'calibration',
  Flashcards = 'flashcards',
  CoderPad = 'coderpad',
  Behavioral = 'behavioral',
  Product = 'product',
  FinalBoss = 'finalboss'
}

export interface AppState {
  currentBlockIndex: number;
  overallReadiness: number;
  scores: {
    technical: number;
    coding: number;
    partner: number;
    product: number;
  };
  completedBlocks: string[];
  flashcardStats: Record<string, { gotIt: boolean; seen: number }>;
  starDrafts: Record<string, string>;
  quizResults: Record<string, number>;
  sessionStartTime?: number;
}

export interface Flashcard {
  id: string;
  deck: 'A' | 'B' | 'C' | 'D';
  question: string;
  answer: string;
  tags: string[];
}

export interface CodingPrompt {
  id: string;
  title: string;
  description: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  hints: string[];
  checklist: string[];
}

export interface Scenario {
  id: string;
  title: string;
  description: string;
  approaches: {
    label: string;
    text: string;
    feedback: string;
    isBest: boolean;
  }[];
  modelStar: string;
}

import { Flashcard, CodingPrompt, Scenario, BlockType } from '../types';

