  { id: BlockType.Calibration, title: "Role Briefing & Calibration", duration: 10, description: "Align expectations and test foundational role knowledge." },
  { id: BlockType.Flashcards, title: "Flashcard Trainer: Foundations", duration: 25, description: "Master technical constraints and SDK patterns." },
  { id: BlockType.CoderPad, title: "CoderPad Simulation", duration: 30, description: "Algorithms and Partner-friendly SDK design." },
  { id: BlockType.Behavioral, title: "Partner & Behavioral Simulator", duration: 25, description: "High-stakes communication and STAR alignment." },
  { id: BlockType.Product, title: "Wearables Product Thinking", duration: 20, description: "Designing for the face: privacy, battery, and AI." },
