export default ProgressPanel;

import React from 'react';

interface Props {
  timeLeft: number;
  isActive: boolean;
  setIsActive: (val: boolean) => void;
  onReset: () => void;
  onSkip: () => void;
  onPrev: () => void;
  isLast: boolean;
  isFirst: boolean;
}

const TimerPanel: React.FC<Props> = ({ timeLeft, isActive, setIsActive, onReset, onSkip, onPrev, isLast, isFirst }) => {
  const formatTime = (seconds: number) => {
    const isNegative = seconds < 0;
    const abs = Math.abs(seconds);
    const m = Math.floor(abs / 60);
    const s = abs % 60;
    return `${isNegative ? '-' : ''}${m}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col items-center">
      <h3 className="text-xs font-bold text-slate-400 uppercase mb-4 tracking-widest">Block Timer</h3>

      <div className={`text-5xl font-mono font-black mb-6 ${timeLeft < 0 ? 'text-red-500 animate-pulse' : 'text-slate-800'}`}>
        {formatTime(timeLeft)}
      </div>

      <div className="w-full grid grid-cols-2 gap-3 mb-6">
        <button 
          onClick={() => setIsActive(!isActive)}
          className={`py-3 px-4 rounded-xl font-bold text-sm transition-all ${isActive ? 'bg-amber-100 text-amber-700 hover:bg-amber-200' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-md shadow-blue-200'}`}
        >
          {isActive ? 'Pause' : 'Start Timer'}
        </button>
        <button 
          onClick={onReset}
          className="py-3 px-4 rounded-xl bg-slate-100 text-slate-600 font-bold text-sm hover:bg-slate-200"
        >
          Reset
        </button>
      </div>

      <div className="w-full flex justify-between gap-4">
         <button 
            disabled={isFirst}
            onClick={onPrev}
            className="flex-1 text-slate-400 hover:text-slate-600 disabled:opacity-30 text-xs font-bold transition-all"
        >
            &larr; Back
        </button>
        <button 
            disabled={isLast}
            onClick={onSkip}
            className="flex-1 text-blue-500 hover:text-blue-700 disabled:opacity-30 text-xs font-bold transition-all"
        >
            Skip Block &rarr;
        </button>
      </div>
    </div>
  );
};

export default TimerPanel;

import React, { useState } from 'react';

const CalibrationBlock: React.FC<{ onComplete: (score: number) => void }> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [answers, setAnswers] = useState<number[]>([]);

  const quiz = [
    { q: "What is the primary technical focus for a Wearables PE?", a: ["Web backend", "Client-side Android/iOS", "Database optimization"], correct: 1 },
    { q: "How does this role interact with the product feedback loop?", a: ["Directing marketing", "Translating partner friction to internal eng", "Writing end-user ads"], correct: 1 },
    { q: "Which hardware constraint is unique to smart glasses?", a: ["Screen size", "Face-borne thermals", "Stylus latency"], correct: 1 }
  ];

  const handleFinish = () => {
    const correctCount = answers.reduce((acc, ans, i) => acc + (ans === quiz[i].correct ? 1 : 0), 0);
    const score = Math.round((correctCount / quiz.length) * 100);
    onComplete(score);
  };

  if (step === 1) {
    return (
      <div className="space-y-6">
        <h3 className="text-xl font-bold text-slate-800">Role Calibration</h3>
        <p className="text-slate-600 leading-relaxed">
          The <strong>Solutions Architect III / Wearables Partner Engineer</strong> is a high-impact technical role. You bridge the gap between Meta's hardware/OS teams and top-tier app developers (Spotify, WhatsApp, Strava, etc.).
        </p>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
            <h4 className="font-bold text-blue-600 mb-2">Core Responsibilities</h4>
            <ul className="text-sm space-y-2 text-slate-600 list-disc ml-4">
              <li>SDK Integration Architecture</li>
              <li>Partner Technical Debugging</li>
              <li>Reality Labs OS/App Platform advocacy</li>
            </ul>
          </div>
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
            <h4 className="font-bold text-emerald-600 mb-2">Key Hard Skills</h4>
            <ul className="text-sm space-y-2 text-slate-600 list-disc ml-4">
              <li>Advanced Android (JNI, BLE, Media)</li>
              <li>AI productivity tools knowledge</li>
              <li>Mobile-first API design</li>
            </ul>
          </div>
        </div>
        <button 
          onClick={() => setStep(2)}
          className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-slate-800 transition-all shadow-lg"
        >
          Begin Role Readiness Quiz
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {quiz.map((item, i) => (
        <div key={i} className="space-y-4">
          <p className="font-bold text-slate-800">{i+1}. {item.q}</p>
          <div className="grid grid-cols-1 gap-2">
            {item.a.map((opt, idx) => (
              <button
                key={idx}
                onClick={() => {
                  const newAnswers = [...answers];
                  newAnswers[i] = idx;
                  setAnswers(newAnswers);
                }}
                className={`p-4 text-left rounded-xl border transition-all ${answers[i] === idx ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-200 hover:border-blue-300'}`}
              >
                {opt}
              </button>
            ))}
          </div>
        </div>
      ))}
      <button 
        disabled={answers.length < quiz.length}
        onClick={handleFinish}
        className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg"
      >
        Submit & Advance
      </button>
    </div>
  );
};

export default CalibrationBlock;

import React, { useState } from 'react';
import { FLASHCARDS } from '../../data/content';
import { AppState } from '../../types';

interface Props {
  onComplete: (score: number) => void;
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
}

const FlashcardBlock: React.FC<Props> = ({ onComplete, state, setState }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [localStats, setLocalStats] = useState<Record<string, boolean>>({});

  const card = FLASHCARDS[currentIndex];

  const handleChoice = (gotIt: boolean) => {
    setLocalStats(prev => ({ ...prev, [card.id]: gotIt }));
    setFlipped(false);
    if (currentIndex < FLASHCARDS.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      // Calculate final score for this block
      const totalGotIt = Object.values({ ...localStats, [card.id]: gotIt }).filter(v => v).length;
      const score = Math.round((totalGotIt / FLASHCARDS.length) * 100);

      // Update global state
      const newStats = { ...state.flashcardStats };
      Object.entries({ ...localStats, [card.id]: gotIt }).forEach(([id, val]) => {
        newStats[id] = { gotIt: val, seen: (newStats[id]?.seen || 0) + 1 };
      });
      setState(prev => ({ ...prev, flashcardStats: newStats }));
      onComplete(score);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center space-y-8">
      <div className="w-full flex justify-between items-center text-xs font-bold text-slate-400 uppercase tracking-widest">
        <span>Deck {card.deck}: {card.tags.join(', ')}</span>
        <span>{currentIndex + 1} / {FLASHCARDS.length}</span>
      </div>

      <div 
        className={`w-full max-w-md aspect-[3/2] relative cursor-pointer transition-all duration-500 [transform-style:preserve-3d] ${flipped ? '[transform:rotateY(180deg)]' : ''}`}
        onClick={() => setFlipped(!flipped)}
      >
        {/* Front */}
        <div className="absolute inset-0 bg-white border-2 border-slate-100 rounded-3xl shadow-xl flex items-center justify-center p-8 text-center [backface-visibility:hidden]">
          <p className="text-xl font-bold text-slate-800">{card.question}</p>
          <div className="absolute bottom-4 text-xs text-slate-300 font-bold uppercase">Click to Flip</div>
        </div>

        {/* Back */}
        <div className="absolute inset-0 bg-blue-600 text-white rounded-3xl shadow-xl flex items-center justify-center p-8 text-center [backface-visibility:hidden] [transform:rotateY(180deg)] overflow-auto">
          <div>
            <p className="text-lg leading-relaxed">{card.answer}</p>
          </div>
        </div>
      </div>

      <div className="flex gap-4 w-full max-w-md">
        <button 
          onClick={() => handleChoice(false)}
          className="flex-1 py-4 px-6 bg-red-50 text-red-600 rounded-2xl font-bold hover:bg-red-100 transition-all border border-red-100"
        >
          Not yet
        </button>
        <button 
          onClick={() => handleChoice(true)}
          className="flex-1 py-4 px-6 bg-emerald-50 text-emerald-600 rounded-2xl font-bold hover:bg-emerald-100 transition-all border border-emerald-100 shadow-sm"
        >
          Got it
        </button>
      </div>
    </div>
  );
};

export default FlashcardBlock;

import React, { useState } from 'react';
import { CODING_PROMPTS } from '../../data/content';

const CoderPadBlock: React.FC<{ onComplete: (score: number) => void }> = ({ onComplete }) => {
  const [selectedPromptIdx, setSelectedPromptIdx] = useState<number | null>(null);
  const [solution, setSolution] = useState("");
  const [checks, setChecks] = useState<Record<string, boolean>>({});

  const prompt = selectedPromptIdx !== null ? CODING_PROMPTS[selectedPromptIdx] : null;

  const handleCheck = (item: string) => {
    setChecks(prev => ({ ...prev, [item]: !prev[item] }));
  };

  const handleFinish = () => {
    if (!prompt) return;
    const checkedCount = Object.values(checks).filter(v => v).length;
    const score = Math.round((checkedCount / prompt.checklist.length) * 100);
    onComplete(score);
  };

  if (selectedPromptIdx === null) {
    return (
      <div className="space-y-6">
        <h3 className="text-xl font-bold text-slate-800">Select a Coding Challenge</h3>
        <div className="grid grid-cols-1 gap-4">
          {CODING_PROMPTS.map((p, i) => (
            <button
              key={p.id}
              onClick={() => setSelectedPromptIdx(i)}
              className="p-6 bg-white border border-slate-200 rounded-2xl text-left hover:border-blue-500 hover:shadow-md transition-all group"
            >
              <div className="flex justify-between mb-2">
                <h4 className="font-bold text-slate-800 group-hover:text-blue-600">{p.title}</h4>
                <span className={`text-[10px] font-black uppercase px-2 py-1 rounded ${p.difficulty === 'Hard' ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>
                    {p.difficulty}
                </span>
              </div>
              <p className="text-sm text-slate-500 line-clamp-2">{p.description}</p>
            </button>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="bg-slate-900 rounded-2xl p-6 text-slate-300">
        <h4 className="text-white font-bold mb-2">Prompt: {prompt?.title}</h4>
        <p className="text-sm leading-relaxed mb-4">{prompt?.description}</p>
        <div className="space-y-2">
           {prompt?.hints.map((h, i) => (
              <p key={i} className="text-[10px] text-slate-500 italic uppercase">Hint {i+1}: {h}</p>
           ))}
        </div>
      </div>

      <textarea 
        value={solution}
        onChange={(e) => setSolution(e.target.value)}
        placeholder="// Write your pseudo-code or solution here..."
        className="w-full h-48 bg-slate-50 border border-slate-200 rounded-2xl p-4 font-mono text-sm focus:ring-2 focus:ring-blue-500 outline-none"
      />

      <div className="bg-slate-50 p-6 rounded-2xl">
        <h4 className="text-sm font-bold text-slate-600 uppercase mb-4">Self-Evaluation Checklist</h4>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          {prompt?.checklist.map((item) => (
            <label key={item} className="flex items-center gap-3 cursor-pointer group">
              <input 
                type="checkbox"
                checked={!!checks[item]}
                onChange={() => handleCheck(item)}
                className="w-5 h-5 rounded-md border-slate-300 text-blue-600 focus:ring-blue-500"
              />
              <span className={`text-sm transition-colors ${checks[item] ? 'text-blue-600 font-medium' : 'text-slate-500'}`}>{item}</span>
            </label>
          ))}
        </div>
      </div>

      <button 
        onClick={handleFinish}
        className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-slate-800 transition-all shadow-lg"
      >
        Save Solution & Evaluation
      </button>
    </div>
  );
};

export default CoderPadBlock;

import React, { useState } from 'react';
import { SCENARIOS } from '../../data/content';
import { AppState } from '../../types';

interface Props {
  onComplete: (score: number) => void;
  state: AppState;
  setState: React.Dispatch<React.SetStateAction<AppState>>;
}

const BehavioralBlock: React.FC<Props> = ({ onComplete, state, setState }) => {
  const [selectedIdx, setSelectedIdx] = useState(0);
  const [choice, setChoice] = useState<number | null>(null);
  const [starDraft, setStarDraft] = useState("");
  const [showModel, setShowModel] = useState(false);

  const scenario = SCENARIOS[selectedIdx];

  const handleNext = () => {
    const isBest = choice !== null && scenario.approaches[choice].isBest;
    const score = isBest ? 100 : 50;

    // Save draft
    setState(prev => ({ 
      ...prev, 
      starDrafts: { ...prev.starDrafts, [scenario.id]: starDraft } 
    }));

    onComplete(score);
  };

  return (
    <div className="space-y-6">
      <div className="bg-purple-50 p-6 rounded-2xl border border-purple-100">
        <h3 className="text-lg font-bold text-purple-900 mb-2">{scenario.title}</h3>
        <p className="text-purple-800/80 leading-relaxed text-sm">{scenario.description}</p>
      </div>

      <div className="space-y-4">
        <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Select your approach:</p>
        {scenario.approaches.map((app, i) => (
          <button
            key={i}
            onClick={() => setChoice(i)}
            className={`w-full p-4 rounded-xl border text-left transition-all ${choice === i ? 'bg-blue-600 border-blue-600 text-white shadow-md' : 'bg-white border-slate-200 hover:border-blue-300'}`}
          >
            <div className="flex gap-4">
              <span className="font-bold opacity-50">{app.label}</span>
              <span className="text-sm">{app.text}</span>
            </div>
          </button>
        ))}
      </div>

      {choice !== null && (
        <div className={`p-4 rounded-xl text-sm font-medium ${scenario.approaches[choice].isBest ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>
          Feedback: {scenario.approaches[choice].feedback}
        </div>
      )}

      <div className="space-y-4 pt-6 border-t border-slate-100">
        <div className="flex justify-between items-center">
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Draft your STAR Response:</p>
            <button 
                onClick={() => setShowModel(!showModel)}
                className="text-xs text-blue-600 font-bold hover:underline"
            >
                {showModel ? 'Hide Model' : 'Show Model STAR'}
            </button>
        </div>

        {showModel && (
            <div className="bg-slate-900 text-blue-300 p-4 rounded-xl text-xs font-mono leading-relaxed italic">
                {scenario.modelStar}
            </div>
        )}

        <textarea 
          value={starDraft}
          onChange={(e) => setStarDraft(e.target.value)}
          placeholder="S: Situation, T: Task, A: Action, R: Result..."
          className="w-full h-32 bg-slate-50 border border-slate-200 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
        />
      </div>

      <button 
        disabled={choice === null}
        onClick={handleNext}
        className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-slate-800 disabled:opacity-50 transition-all shadow-lg"
      >
        Finalize Behavioral Prep
      </button>
    </div>
  );
};

export default BehavioralBlock;

