};

export default ProductBlock;

import React, { useState } from 'react';
import { AppState } from '../../types';

interface Props {
  state: AppState;
  onReset: () => void;
}

const FinalBossBlock: React.FC<Props> = ({ state, onReset }) => {
  const [ratings, setRatings] = useState<number[]>([]);

  const questions = [
    "Explain the importance of 'Latency' in a Wearables SDK.",
    "How would you handle a partner demanding a private API access?",
    "Describe a trade-off between AI feature richness and glass battery life.",
    "What is your unique value proposition to Meta Reality Labs?"
  ];

  const handleRating = (qIdx: number, val: number) => {
    const newRatings = [...ratings];
    newRatings[qIdx] = val;
    setRatings(newRatings);
  };

  const isFinished = ratings.length === questions.length && ratings.every(r => r !== undefined);

  if (isFinished) {
    return (
      <div className="space-y-8 animate-in fade-in duration-700">
        <div className="text-center">
            <h3 className="text-3xl font-black text-slate-900 mb-2">Readiness Check: {state.overallReadiness}%</h3>
            <p className="text-slate-500">You've completed the intensive Meta prep session.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <h4 className="font-bold text-slate-800 mb-4">Strengths</h4>
                <div className="space-y-2">
                    {state.scores.technical > 70 && <p className="text-sm text-emerald-600 font-medium">&bull; Strong Technical Foundations</p>}
                    {state.scores.coding > 70 && <p className="text-sm text-emerald-600 font-medium">&bull; CoderPad Readiness High</p>}
                    {state.scores.partner > 70 && <p className="text-sm text-emerald-600 font-medium">&bull; Solid Partner-Facing Soft Skills</p>}
                    {state.scores.product > 70 && <p className="text-sm text-emerald-600 font-medium">&bull; Wearables Mindset present</p>}
                </div>
            </div>
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                <h4 className="font-bold text-slate-800 mb-4">Focus Areas</h4>
                <div className="space-y-2">
                    {state.scores.technical <= 70 && <p className="text-sm text-amber-600 font-medium">&bull; Revisit Technical constraints flashcards</p>}
                    {state.scores.coding <= 70 && <p className="text-sm text-amber-600 font-medium">&bull; Practice more SDK design challenges</p>}
                    {state.scores.partner <= 70 && <p className="text-sm text-amber-600 font-medium">&bull; Refine STAR stories for partner friction</p>}
                </div>
            </div>
        </div>

        <button 
          onClick={() => {
            if (window.confirm("This will clear all progress. Are you sure?")) {
              onReset();
            }
          }}
          className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-bold hover:bg-slate-200 transition-all"
        >
          Reset Session & Practice Again
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-10">
      <p className="text-slate-600">Answer these out loud to simulate the interview. Rate your performance (1-5).</p>
      {questions.map((q, i) => (
        <div key={i} className="space-y-4">
          <p className="font-bold text-slate-800 text-lg leading-tight">{q}</p>
          <div className="flex gap-2">
            {[1, 2, 3, 4, 5].map(v => (
              <button 
                key={v}
                onClick={() => handleRating(i, v)}
                className={`flex-1 py-3 rounded-xl border font-bold transition-all ${ratings[i] === v ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 hover:bg-slate-50 text-slate-400'}`}
              >
                {v}
              </button>
            ))}
          </div>
        </div>
      ))}
      <div className="pt-6">
        <p className="text-center text-xs text-slate-400 mb-4">Complete all ratings to see final evaluation.</p>
      </div>
    </div>
  );
};

export default FinalBossBlock;

