              </div>
            </div>
            <hr className="mb-8 border-slate-100" />
            {renderBlock()}
          </div>
        </div>

        <div className="lg:col-span-3 space-y-6">
          <TimerPanel 
            timeLeft={timeLeft} 
            isActive={isActive} 
            setIsActive={setIsActive} 
