          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 p-4 text-center text-slate-400 text-xs">
        Reality Labs Partner Prep &bull; Data persisted locally &bull; 2024
      </footer>
    </div>
  );
};

