          </div>
          {state.history.length > 0 && (
             <button 
                onClick={() => setView('history')}
                className="w-full bg-slate-900 hover:bg-slate-800 text-white p-4 rounded-2xl font-bold text-sm shadow-lg shadow-slate-200 flex items-center justify-center gap-2 transition-all"
             >
                📋 View History Log ({state.history.length})
             </button>
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 p-4 text-center text-slate-400 text-xs">
        Reality Labs Partner Prep &bull; Data persisted locally &bull; 2024
      </footer>
    </div>
  );
};

