import React, { useState, useEffect } from 'react';
import { REFRESHER_TOPICS } from '../../data/content';

const RefresherBlock: React.FC<{ onComplete: (score: number) => void }> = ({ onComplete }) => {
  const [activeIdx, setActiveIdx] = useState(0);
  const [practiceInput, setPracticeInput] = useState("");
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [showHint, setShowHint] = useState(false);
  const [showSolution, setShowSolution] = useState(false);
  const [failCount, setFailCount] = useState(0);
  const [scores, setScores] = useState<number[]>([]);

  const topic = REFRESHER_TOPICS[activeIdx];

  useEffect(() => {
    setPracticeInput("");
    setIsCorrect(null);
    setShowHint(false);
    setShowSolution(false);
    setFailCount(0);
  }, [activeIdx]);

  const checkAnswer = () => {
    // Normalization for comparison (ignoring minor spacing differences)
    const normalize = (s: string) => s.replace(/\s+/g, ' ').replace(/['"]/g, "'").trim();

    const cleanInput = normalize(practiceInput);
    const cleanCorrect = normalize(topic.practiceCorrect);

    if (cleanInput === cleanCorrect || practiceInput.trim() === topic.practiceCorrect.trim()) {
      setIsCorrect(true);
      const newScores = [...scores];
      newScores[activeIdx] = 100;
      setScores(newScores);
    } else {
      setIsCorrect(false);
      setFailCount(prev => prev + 1);
    }
  };

  const handleNext = () => {
    if (activeIdx < REFRESHER_TOPICS.length - 1) {
      setActiveIdx(prev => prev + 1);
    } else {
      const totalScore = scores.reduce((a, b) => a + (b || 0), 0) / REFRESHER_TOPICS.length;
      onComplete(Math.round(totalScore || 100));
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center">
        <div>
           <h3 className="text-xl font-bold text-slate-800">{topic.title}</h3>
           <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Foundational Lab {activeIdx + 1} of {REFRESHER_TOPICS.length}</p>
        </div>
        <div className="flex gap-1">
          {REFRESHER_TOPICS.map((_, i) => (
            <div key={i} className={`w-2 h-2 rounded-full ${i === activeIdx ? 'bg-blue-600' : scores[i] ? 'bg-emerald-400' : 'bg-slate-200'}`} />
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Theory Column */}
        <div className="space-y-4">
          <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 space-y-4">
            <div>
              <h4 className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">The Rule</h4>
              <p className="text-slate-700 text-sm leading-relaxed font-medium">{topic.concept}</p>
            </div>

            <div className="space-y-2">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Anatomy Breakdown</h4>
              <div className="grid grid-cols-1 gap-1">
                {topic.anatomy.map((item, i) => (
                  <div key={i} className="flex items-center gap-2 text-[11px] text-slate-600">
                    <span className="w-1.5 h-1.5 rounded-full bg-blue-400"></span>
                    {item}
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-white p-4 rounded-xl border border-slate-100">
              <h4 className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Visualization</h4>
              <p className="text-slate-600 text-xs italic">"{topic.analogy}"</p>
            </div>

            <div>
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Reference Code</h4>
              <pre className="bg-slate-900 text-blue-300 p-4 rounded-xl text-[11px] font-mono leading-relaxed border border-slate-800 shadow-inner">
                {topic.example}
              </pre>
            </div>
          </div>
        </div>

        {/* Practice Column */}
        <div className="space-y-4 flex flex-col">
          <div className="flex-1 bg-slate-900 rounded-2xl p-6 flex flex-col shadow-2xl">
            <h4 className="text-[10px] font-black text-amber-400 uppercase tracking-widest mb-3">Syntax Sandbox</h4>
            <p className="text-white text-sm font-semibold mb-4 leading-relaxed">{topic.practicePrompt}</p>

            <div className="relative flex-1 min-h-[160px]">
              <textarea 
                value={practiceInput}
                onChange={(e) => setPracticeInput(e.target.value)}
                placeholder={topic.practicePlaceholder}
                spellCheck={false}
                className={`w-full h-full bg-slate-800 text-emerald-400 p-4 rounded-xl font-mono text-sm border-2 outline-none resize-none transition-all ${isCorrect === true ? 'border-emerald-500 bg-emerald-900/10' : isCorrect === false ? 'border-red-500 bg-red-900/10' : 'border-slate-700 focus:border-blue-500'}`}
              />
              {isCorrect === true && (
                <div className="absolute top-4 right-4 bg-emerald-500 text-white p-1 rounded-full animate-bounce">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                </div>
              )}
            </div>

            <div className="mt-4 flex flex-wrap gap-2">
              <button 
                onClick={checkAnswer}
                className="bg-blue-600 hover:bg-blue-700 text-white text-xs font-bold px-6 py-2.5 rounded-lg transition-all shadow-lg active:scale-95"
              >
                Run Tests
              </button>
              <button 
                onClick={() => setShowHint(!showHint)}
                className="text-slate-400 hover:text-white text-xs font-bold px-3 py-2 transition-colors"
              >
                {showHint ? 'Hide Hint' : 'Show Hint'}
              </button>
              {(failCount >= 1 || isCorrect === false) && (
                 <button 
                    onClick={() => setShowSolution(!showSolution)}
                    className="text-amber-500 hover:text-amber-400 text-xs font-bold px-3 py-2 transition-colors border border-amber-500/30 rounded-lg ml-auto"
                 >
                    {showSolution ? 'Hide Solution' : 'Reveal Solution'}
                 </button>
              )}
            </div>

            {showHint && (
              <div className="mt-3 text-[11px] text-amber-200 bg-amber-900/40 p-3 rounded-lg border border-amber-800/50 animate-in fade-in slide-in-from-top-1">
                <strong>Tip:</strong> Look at the {topic.anatomy[0].split(':')[0]} in the anatomy guide. Ensure your variable name matches the prompt exactly.
              </div>
            )}

            {showSolution && (
              <div className="mt-3 text-[11px] text-emerald-300 bg-emerald-900/40 p-3 rounded-lg border border-emerald-800/50 animate-in fade-in slide-in-from-top-1 font-mono">
                Correct Syntax: <br/>
                <code className="text-white bg-black/40 px-2 py-1 rounded mt-1 inline-block">{topic.practiceCorrect}</code>
              </div>
            )}

            {isCorrect === false && !showSolution && (
              <p className="mt-2 text-red-400 text-[11px] font-bold animate-pulse">
                Try again! Check your braces {} or semicolons ;
              </p>
            )}
          </div>
        </div>
      </div>

      <div className="flex gap-4 pt-4 border-t border-slate-100">
        <button 
          onClick={() => setActiveIdx(Math.max(0, activeIdx - 1))}
          disabled={activeIdx === 0}
          className="px-8 py-4 rounded-2xl font-bold text-slate-500 bg-slate-100 hover:bg-slate-200 disabled:opacity-30 transition-all"
        >
          Previous
        </button>
        <button 
          onClick={handleNext}
          className={`flex-1 py-4 rounded-2xl font-bold shadow-lg transition-all ${isCorrect ? 'bg-slate-900 text-white hover:bg-slate-800' : 'bg-slate-200 text-slate-400 cursor-not-allowed'}`}
          disabled={!isCorrect}
        >
          {activeIdx === REFRESHER_TOPICS.length - 1 ? 'Finish Bootcamp' : 'Next Lesson'}
        </button>
      </div>
    </div>
  );
};

export default RefresherBlock;

import React, { useState } from 'react';

const CalibrationBlock: React.FC<{ onComplete: (score: number) => void }> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [answers, setAnswers] = useState<number[]>([]);

  const quiz = [
    { q: "What is the primary technical focus for a Wearables PE?", a: ["Web backend", "Client-side Android/iOS", "Database optimization"], correct: 1 },
    { q: "How does this role interact with the product feedback loop?", a: ["Directing marketing", "Translating partner friction to internal eng", "Writing end-user ads"], correct: 1 },
    { q: "Which hardware constraint is unique to smart glasses?", a: ["Screen size", "Face-borne thermals", "Stylus latency"], correct: 1 },
    { q: "In a 'Thin Client' model, where does the NLP processing usually happen?", a: ["On the glasses", "On the paired smartphone", "On a 3rd party server"], correct: 1 },
    { q: "What is the consequence of high Motion-to-Photon latency?", a: ["Blurred photos", "Motion sickness", "Battery overheating"], correct: 1 },
    { q: "What is the role of an HRTF in wearables?", a: ["Heart Rate Tracking", "Spatial Audio filtering", "High Resolution Texture Filing"], correct: 1 },
    { q: "Why is 'Duty Cycling' important for wearable sensors?", a: ["To increase accuracy", "To preserve battery life", "To simplify the code"], correct: 1 }
  ];

  const handleFinish = () => {
    const correctCount = answers.reduce((acc, ans, i) => acc + (ans === quiz[i].correct ? 1 : 0), 0);
    const score = Math.round((correctCount / quiz.length) * 100);
    onComplete(score);
  };

  if (step === 1) {
    return (
      <div className="space-y-6">
        <h3 className="text-xl font-bold text-slate-800">Role Calibration</h3>
        <p className="text-slate-600 leading-relaxed">
          The <strong>Solutions Architect III / Wearables Partner Engineer</strong> is a high-impact technical role. You bridge the gap between Meta's hardware/OS teams and top-tier app developers.
        </p>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
            <h4 className="font-bold text-blue-600 mb-2">Core Responsibilities</h4>
            <ul className="text-sm space-y-2 text-slate-600 list-disc ml-4">
              <li>SDK Integration Architecture</li>
              <li>Partner Technical Debugging</li>
              <li>Reality Labs OS advocacy</li>
            </ul>
          </div>
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
            <h4 className="font-bold text-emerald-600 mb-2">Key Hard Skills</h4>
            <ul className="text-sm space-y-2 text-slate-600 list-disc ml-4">
              <li>Android Internals (JNI, BLE)</li>
              <li>Spatial Computing Concepts</li>
              <li>Mobile-first API design</li>
            </ul>
          </div>
        </div>
        <button 
          onClick={() => setStep(2)}
          className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-slate-800 transition-all shadow-lg"
        >
          Begin Role Readiness Quiz
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-8 max-h-[60vh] overflow-y-auto pr-4 custom-scrollbar">
      {quiz.map((item, i) => (
        <div key={i} className="space-y-4 animate-in slide-in-from-right-2" style={{ animationDelay: `${i * 100}ms` }}>
          <p className="font-bold text-slate-800 text-sm">{i+1}. {item.q}</p>
          <div className="grid grid-cols-1 gap-2">
            {item.a.map((opt, idx) => (
              <button
                key={idx}
                onClick={() => {
                  const newAnswers = [...answers];
                  newAnswers[i] = idx;
                  setAnswers(newAnswers);
                }}
                className={`p-3 text-left rounded-xl border text-sm transition-all ${answers[i] === idx ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-200 hover:border-blue-300'}`}
              >
                {opt}
              </button>
            ))}
          </div>
        </div>
      ))}
      <div className="sticky bottom-0 bg-white pt-4">
          <button 
            disabled={answers.filter(a => a !== undefined).length < quiz.length}
            onClick={handleFinish}
            className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-lg"
          >
            Submit Calibration Quiz
          </button>
      </div>
    </div>
  );
};

